module.exports = function (results) {
  const errors = [];
  const warnings = [];

  results.forEach((result) => {
    const filePath = result.filePath;
    result.messages.forEach((msg) => {
      const entry = {
        filePath,
        line: msg.line,
        column: msg.column,
        severity: msg.severity,
        message: msg.message,
        ruleId: msg.ruleId || '',
      };
      if (msg.severity === 2) {
        errors.push(entry);
      } else {
        warnings.push(entry);
      }
    });
  });

  const sorted = [...errors, ...warnings];

  if (sorted.length === 0) {
    return '';
  }

  let output = '';
  let currentFile = '';

  sorted.forEach((entry) => {
    if (entry.filePath !== currentFile) {
      currentFile = entry.filePath;
      output += `\n${currentFile}\n`;
    }
    const severity = entry.severity === 2 ? 'error' : 'warning';
    output += `  ${entry.line}:${entry.column}  ${severity}  ${entry.message}  ${entry.ruleId}\n`;
  });

  const errorCount = errors.length;
  const warningCount = warnings.length;
  const total = errorCount + warningCount;

  output += `\n\u2716 ${total} problem${total !== 1 ? 's' : ''} (${errorCount} error${errorCount !== 1 ? 's' : ''}, ${warningCount} warning${warningCount !== 1 ? 's' : ''})\n`;

  return output;
};

