    });
  });

  let output = '';
  let totalProblems = 0;

  if (errors.length > 0) {
    output += '\n[ESLINT ERRORS]\n';
    errors.forEach(e => {
      output += `  Error: ${e.message} (${e.ruleId})\n`;
      output += `  at ${e.filePath}:${e.line}:${e.column}\n\n`;
    });
    totalProblems += errors.length;
  }

  if (warnings.length > 0) {
    output += '\n[ESLINT WARNINGS]\n';
    warnings.forEach(w => {
      output += `  Warning: ${w.message} (${w.ruleId})\n`;
      output += `  at ${w.filePath}:${w.line}:${w.column}\n\n`;
    });
    totalProblems += warnings.length;
  }

  if (totalProblems > 0) {
    output += `\n✖ ${totalProblems} problems (${errors.length} errors, ${warnings.length} warnings)\n`;
  } else {
    output += '\n✔ No problems found!\n';
  }

  return output;
};
